 1	import * as React from 'react';
 2	
 3	import LabelsList from '@kubevirt-utils/components/NodeSelectorModal/components/LabelList';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { GridItem, Text, TextVariants } from '@patternfly/react-core';
 6	
 7	import { AffinityLabel } from '../../../../utils/types';
 8	
 9	import AffinityEditRow from './AffinityEditRow';
10	
11	type AffinityExpressionListProps = {
12	  addRowText: string;
13	  expressions: AffinityLabel[];
14	  onAdd: () => void;
15	  onChange: (aff: AffinityLabel) => void;
16	  onDelete: (id: any) => void;
17	  rowID: string;
18	};
19	
20	const AffinityEditList: React.FC<AffinityExpressionListProps> = ({
21	  addRowText,
22	  expressions,
23	  onAdd,
24	  onChange,
25	  onDelete,
26	  rowID,
27	}) => {
28	  const { t } = useKubevirtTranslation();
29	
30	  return (
31	    <LabelsList
32	      addRowText={addRowText}
33	      emptyStateAddRowText={addRowText}
34	      isEmpty={expressions?.length === 0}
35	      onLabelAdd={onAdd}
36	    >
37	      {expressions.length > 0 && (
38	        <>
39	          <GridItem span={4}>
40	            <Text component={TextVariants.h6}>{t('Key')}</Text>
41	          </GridItem>
42	          <GridItem span={2}>
43	            <Text component={TextVariants.h6}>{t('Operator')}</Text>
44	          </GridItem>
45	          <GridItem span={6}>
46	            <Text component={TextVariants.h6}>{t('Values')}</Text>
47	          </GridItem>
48	          {expressions.map((expression) => (
49	            <AffinityEditRow
50	              expression={expression}
51	              key={expression.id}
52	              onChange={onChange}
53	              onDelete={onDelete}
54	              rowID={rowID}
55	            />
56	          ))}
57	        </>
58	      )}
59	    </LabelsList>
60	  );
61	};
62	
63	export default AffinityEditList;

